SELECT MAX(total_vehicle_kms) AS highest_total_kms
  FROM vehicle_usage
  WHERE dataset_id = 0;

SELECT file_name
FROM transit_data_sets
WHERE peak_hour_flag = 1;

SELECT dataset_id, file_name
FROM transit_data_sets
ORDER BY dataset_id, file_name;

SELECT total_pass_count
FROM transit_data_sets
WHERE dataset_id = 1;

SELECT file_name
FROM transit_data_sets
WHERE total_travel_time = (SELECT MAX(total_travel_time) FROM transit_data_sets);

SELECT AVG(travel_time_per_passenger) AS overall_avg_travel_time_during_peak_hours
FROM transit_data_sets
WHERE peak_hour_flag = 1;

SELECT satisfaction_rating
FROM passenger_statistics
WHERE dataset_id = 1;

SELECT file_name, total_pass_count
FROM transit_data_sets
ORDER BY total_pass_count DESC;

SELECT travel_time_per_passenger AS average_travel_time
FROM transit_data_sets
WHERE dataset_id = 0;

SELECT dataset_id
FROM transit_data_sets
ORDER BY dataset_id ASC;

SELECT dataset_id
FROM transit_data_sets
ORDER BY dataset_id;
